import { Component, inject, signal, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-setup-password',
  standalone: true,
  imports: [FormsModule],
  template: `
    <div class="auth-page">
      <div class="auth-card">
        <div class="auth-logo">
          <span class="material-icons">lock_reset</span>
          <h1>Set your password</h1>
          <p>Welcome! Create a password to activate your account.</p>
        </div>

        @if (error()) { <div class="alert alert-danger">{{ error() }}</div> }
        @if (success()) { <div class="alert alert-success">Password set! Redirecting to login…</div> }

        @if (!success()) {
          <form (ngSubmit)="submit()">
            <div class="form-group">
              <label>New password</label>
              <input type="password" [(ngModel)]="password" name="pw" required
                     placeholder="At least 8 characters" />
            </div>
            <div class="form-group">
              <label>Confirm password</label>
              <input type="password" [(ngModel)]="confirm" name="confirm" required
                     placeholder="Repeat password" />
            </div>
            <button type="submit" class="btn btn-primary" style="width:100%;" [disabled]="loading()">
              @if (loading()) { Saving… } @else { Activate account }
            </button>
          </form>
        }
      </div>
    </div>
  `,
  styleUrl: '../login/login.scss'
})
export class SetupPasswordComponent implements OnInit {
  password = '';
  confirm  = '';
  error    = signal('');
  success  = signal(false);
  loading  = signal(false);
  token    = '';

  private auth   = inject(AuthService);
  private route  = inject(ActivatedRoute);
  private router = inject(Router);

  ngOnInit(): void {
    this.token = this.route.snapshot.queryParamMap.get('token') ?? '';
    if (!this.token) this.error.set('Invalid or missing setup token.');
  }

  submit(): void {
    if (this.password !== this.confirm) { this.error.set('Passwords do not match.'); return; }
    if (this.password.length < 8)      { this.error.set('Password must be at least 8 characters.'); return; }
    this.error.set('');
    this.loading.set(true);
    this.auth.setupPassword({ token: this.token, password: this.password, confirmPassword: this.confirm }).subscribe({
      next: () => {
        this.success.set(true);
        setTimeout(() => this.router.navigate(['/auth/login']), 2000);
      },
      error: (e: Error) => { this.error.set(e.message); this.loading.set(false); }
    });
  }
}
